// Config plugin: sign release builds with the keystore in mobile/keystore/.
//
// android/ is gitignored and regenerated by `expo prebuild`, so the signing
// config can't live there — this plugin re-injects it into the generated
// android/app/build.gradle on every prebuild. Credentials are read at build
// time from mobile/keystore/keystore.properties (gitignored), so nothing
// secret is committed and no global ~/.gradle/gradle.properties is needed.
const { withAppBuildGradle } = require("expo/config-plugins");

const RELEASE_SIGNING = `    signingConfigs {
        release {
            // Loaded at build time; see mobile/keystore/keystore.properties.
            def keystoreProps = new Properties()
            def keystorePropsFile = rootProject.file('../keystore/keystore.properties')
            if (keystorePropsFile.exists()) {
                keystoreProps.load(new FileInputStream(keystorePropsFile))
            } else {
                logger.warn('mobile/keystore/keystore.properties not found - release signing will fail')
            }
            // Groovy truthiness: empty string counts as unset, so a blank
            // keyPassword= line falls back to the store password.
            def ksStorePassword = keystoreProps.getProperty('storePassword')
            def ksKeyPassword = keystoreProps.getProperty('keyPassword')
            def ksKeyAlias = keystoreProps.getProperty('keyAlias')
            storeFile rootProject.file('../keystore/release.keystore')
            storePassword ksStorePassword
            keyAlias(ksKeyAlias ? ksKeyAlias : 'bettervpn')
            keyPassword(ksKeyPassword ? ksKeyPassword : ksStorePassword)
        }
        debug {`;

module.exports = function withReleaseSigning(config) {
  return withAppBuildGradle(config, (mod) => {
    let gradle = mod.modResults.contents;
    if (gradle.includes("keystore.properties")) return mod; // already applied

    const debugAnchor = "    signingConfigs {\n        debug {";
    if (!gradle.includes(debugAnchor)) {
      throw new Error("with-release-signing: signingConfigs block not found in app/build.gradle");
    }
    gradle = gradle.replace(debugAnchor, RELEASE_SIGNING);

    const releaseAnchor =
      "            // Caution! In production, you need to generate your own keystore file.\n" +
      "            // see https://reactnative.dev/docs/signed-apk-android.\n" +
      "            signingConfig signingConfigs.debug";
    if (!gradle.includes(releaseAnchor)) {
      throw new Error("with-release-signing: release buildType anchor not found in app/build.gradle");
    }
    gradle = gradle.replace(releaseAnchor, "            signingConfig signingConfigs.release");

    mod.modResults.contents = gradle;
    return mod;
  });
};
